// 临时冒烟文件:niceeval 节点 1.5 rubric 制用例验证(t.group + t.score + t.judge…points),验证后删除。
import { defineScoreEval } from "niceeval";

export default defineScoreEval({
  description: "smoke: rubric-style scoring (t.group + t.score + t.judge.points)",
  judge: { model: "gpt-5.4" },
  async test(t) {
    await t.send("Explain briefly why retries need a jitter, and mention the risk of not having one.");

    await t.group("correctness", async () => {
      t.check(t.reply, { name: "nonEmpty", severity: "gate", score: (v) => (typeof v === "string" && v.length > 0 ? 1 : 0) }).points(60);
    });

    await t.group("quality", async () => {
      t.score("brevity", t.reply.length < 500 ? 20 : 0);
      t.judge.autoevals.closedQA("Does the answer mention jitter and the risk of thundering herd / retry storms?").points(20);
    });
  },
});
